mapper.select:
SELECT LAST_SEQ
FROM TBL_NO_MASTER
WHERE YEAR = #{year}
AND APPROVAL_FORM_ID = #{formId}
FOR UPDATE

mapper.update:
UPDATE TBL_NO_MASTER
SET LAST_SEQ = LAST_SEQ + 1,
UPDATE_DATE = NOW()
WHERE YEAR = #{year}
AND APPROVAL_FORM_ID = #{formId}

mapper.select:
SELECT COUNT(*)
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND APPROVER_ID = #{processorId}
AND APPROVE_STATUS = '02'
AND APPROVE_TYPE IN ('02', '03')

SELECT
CASE WHEN COUNT(*) = 0 THEN 1 ELSE 0 END
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND STEP_SEQ > (
SELECT STEP_SEQ
FROM TBL_APRLINE
WHERE DOC_ID = #{docId}
AND APPROVER_ID = #{processorId}
)
AND APPROVE_TYPE = '02'

mapper.update:
UPDATE TBL_APRLINE
SET
APPROVE_STATUS = '02'
WHERE DOC_ID = #{docId}
AND STEP_SEQ = #{stepSeq}
AND APPROVE_STATUS = '01'

mapper.select:
SELECT
S.DOC_ID,
S.DOC_TITLE,
S.DRAFTER,
S.CURR_APPROVER_NAME,
S.DOC_STATUS,
S.UPDATE_DATE
FROM TBL_STATUS_MAP S
WHERE 1=1




        AND S.CURR_APPROVER = #{loginMemId}
        AND S.DOC_STATUS = '02'




        AND S.DRAFTER = #{loginMemId}




        AND S.DRAFTER_DEPT = #{loginDeptCode}




        AND S.DOC_STATUS = '03'
        AND (
        S.DRAFTER = #{loginMemId}
        OR EXISTS (
        SELECT 1 FROM TBL_APRLINE L
        WHERE L.DOC_ID = S.DOC_ID AND L.APPROVER_ID = #{loginMemId}
        )
        )





    AND S.DOC_TITLE LIKE CONCAT('%', #{searchKeyword}, '%')


ORDER BY S.UPDATE_DATE DESC
